// components/navbar/NavbarAdmin.tsx
"use client";

import { useEffect, useState } from "react";
import Cookies from "js-cookie";
import { useRouter } from "next/navigation";
import Navbar from "./Navbar";
import contenidoJson from "@/public/contenido.json";

export default function NavbarAdmin() {
  const [tokenExists, setTokenExists] = useState(false);
  const router = useRouter();

  useEffect(() => {
    const token = Cookies.get("token");
    if (token) setTokenExists(true);
  }, []);

  if (!tokenExists) return null;

  const sections = Object.keys(contenidoJson)
    .filter((key) => Array.isArray(contenidoJson[key]))
    .map((key) => ({
      nombre: key.charAt(0).toUpperCase() + key.slice(1),
      href: `/dashboard#${key}`,
    }));

  const handleLogout = () => {
    router.push("/logout");
  };

  return (
    <Navbar
      name="Panel Admin"
      links={[
        ...sections,
        { nombre: "Cerrar sesión", href: "#", onClick: handleLogout },
      ]}
    />
  );
}
